<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Maze Bots</title>
<style>
  body{font-family:Arial,Helvetica,sans-serif;margin:0;padding:20px;background:#222;color:#eee;}
  #hud{margin-bottom:10px;}
  #maze{border:2px solid #555; background:#111;}
  button{padding:5px 10px;font-size:14px;}
</style>
</head>
<body>

<div id="hud">
  <span>#completed: <span id="completed">0</span></span> |
  <span>#timer: <span id="timer">0</span> ms</span> |
  <button id="reset">Reset</button>
</div>
<canvas id="maze" width="400" height="400"></canvas>

<script>
(() => {
  const CELL_SIZE = 20; // 20px per cell
  const MAZE_COLS = 15;
  const MAZE_ROWS = 15;
  const BOT_COUNT = 24;

  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');

  // Maze representation: each cell has walls {top,right,bottom,left}
  class Cell {
    constructor(x, y) { this.x=x; this.y=y; this.walls={t:true,r:true,b:true,l:true}; this.visited=false;}
  }

  const grid = Array.from({length:MAZE_ROWS}, (_,y)=>Array.from({length:MAZE_COLS}, (_,x)=>new Cell(x,y)));

  // Generate perfect maze via recursive backtracker
  function generateMaze() {
    const stack=[];
    let current=grid[0][0];
    current.visited=true;
    do{
      const neighbors = [];
      if(current.y>0 && !grid[current.y-1][current.x].visited) neighbors.push(grid[current.y-1][current.x]);
      if(current.x<MAZE_COLS-1 && !grid[current.y][current.x+1].visited) neighbors.push(grid[current.y][current.x+1]);
      if(current.y<MAZE_ROWS-1 && !grid[current.y+1][current.x].visited) neighbors.push(grid[current.y+1][current.x]);
      if(current.x>0 && !grid[current.y][current.x-1].visited) neighbors.push(grid[current.y][current.x-1]);

      if(neighbors.length){
        const next = neighbors[Math.floor(Math.random()*neighbors.length)];
        // Remove walls between current and next
        if(next.x===current.x+1){ current.walls.r=false; next.walls.l=false;}
        else if(next.x===current.x-1){ current.walls.l=false; next.walls.r=false;}
        else if(next.y===current.y+1){ current.walls.b=false; next.walls.t=false;}
        else if(next.y===current.y-1){ current.walls.t=false; next.walls.b=false;}

        stack.push(current);
        current=next;
        current.visited=true;
      }else{
        current=stack.pop();
      }
    }while(stack.length);
  }

  generateMaze();

  const startCell = grid[0][0];
  const exitCell = grid[MAZE_ROWS-1][MAZE_COLS-1];

  // BFS to find path from start to exit
  function bfsPath() {
    const queue=[[startCell,[]]];
    const seen=new Set();
    seen.add(startCell);
    while(queue.length){
      const [cell,path]=queue.shift();
      if(cell===exitCell) return [...path,cell];
      const dirs=[{dx:0,dy:-1,w:'t',op:'b'}, {dx:1,dy:0,w:'r',op:'l'},
                  {dx:0,dy:1,w:'b',op:'t'}, {dx:-1,dy:0,w:'l',op:'r'}];
      for(const d of dirs){
        const nx=cell.x+d.dx, ny=cell.y+d.dy;
        if(nx<0||nx>=MAZE_COLS||ny<0||ny>=MAZE_ROWS) continue;
        const neighbor=grid[ny][nx];
        if(cell.walls[d.w]===false && !seen.has(neighbor)){
          seen.add(neighbor);
          queue.push([neighbor,[...path,cell]]);
        }
      }
    }
  }

  const pathCells = bfsPath(); // array of cells from start to exit

  // Bot definition
  class Bot {
    constructor(id){
      this.id=id;
      this.reset();
    }
    reset(){
      this.x=startCell.x; this.y=startCell.y;
      this.stepIndex=0; // index in pathCells
      this.finished=false;
    }
    advance(){
      if(this.finished) return;
      if(this.stepIndex+1>=pathCells.length){
        this.finished=true;
        return;
      }
      this.stepIndex++;
      const cell = pathCells[this.stepIndex];
      this.x=cell.x; this.y=cell.y;
    }
  }

  const bots = Array.from({length:BOT_COUNT}, (_,i)=>new Bot(i));

  // Rendering
  function draw(){
    ctx.fillStyle='#111';
    ctx.fillRect(0,0,CELL_SIZE*MAZE_COLS,CELL_SIZE*MAZE_ROWS);
    // Draw walls
    ctx.strokeStyle='#555';
    ctx.lineWidth=2;
    for(let y=0;y<MAZE_ROWS;y++){
      for(let x=0;x<MAZE_COLS;x++){
        const cell=grid[y][x];
        const px=x*CELL_SIZE, py=y*CELL_SIZE;
        if(cell.walls.t){ctx.beginPath(); ctx.moveTo(px,py); ctx.lineTo(px+CELL_SIZE,py); ctx.stroke();}
        if(cell.walls.r){ctx.beginPath(); ctx.moveTo(px+CELL_SIZE,py); ctx.lineTo(px+CELL_SIZE,py+CELL_SIZE); ctx.stroke();}
        if(cell.walls.b){ctx.beginPath(); ctx.moveTo(px+CELL_SIZE,py+CELL_SIZE); ctx.lineTo(px,py+CELL_SIZE); ctx.stroke();}
        if(cell.walls.l){ctx.beginPath(); ctx.moveTo(px,py+CELL_SIZE); ctx.lineTo(px,py); ctx.stroke();}
      }
    }
    // Draw exit
    ctx.fillStyle='#0f0';
    ctx.fillRect(exitCell.x*CELL_SIZE+4,exitCell.y*CELL_SIZE+4,CELL_SIZE-8,CELL_SIZE-8);
    // Draw bots
    for(const bot of bots){
      if(bot.finished) continue;
      const bx=bot.x*CELL_SIZE+CELL_SIZE/2;
      const by=bot.y*CELL_SIZE+CELL_SIZE/2;
      ctx.beginPath();
      ctx.arc(bx,by,CELL_SIZE/4,0,Math.PI*2);
      ctx.fillStyle='#ff0';
      ctx.fill();
    }
  }

  // HUD
  const completedEl=document.getElementById('completed');
  const timerEl=document.getElementById('timer');

  let startTime=performance.now();
  let elapsedMs=0;
  function updateHUD(){
    completedEl.textContent = bots.filter(b=>b.finished).length;
    timerEl.textContent = Math.floor(elapsedMs);
  }

  function tickFrame(){
    const now=performance.now();
    elapsedMs=now-startTime;
    updateHUD();
    draw();
    requestAnimationFrame(tickFrame);
  }
  requestAnimationFrame(tickFrame);

  // API
  window.game={
    get bots(){return bots.map(b=>({x:b.x,y:b.y}));},
    get completed(){return bots.filter(b=>b.finished).length;},
    get elapsedMs(){return Math.floor(elapsedMs);},
    tick(n){
      for(let i=0;i<n;i++){
        for(const bot of bots) bot.advance();
      }
      draw();
    },
    reset(){
      startTime=performance.now();
      for(const bot of bots) bot.reset();
      draw();
    }
  };

  // Reset button
  document.getElementById('reset').addEventListener('click',()=>window.game.reset());
})();
</script>
</body>
</html>
